// --- START OF OFFLINE CACHE AND SYNC ENGINE ---
const originalFetch = window.fetch;

function updateLocalCache(url: string, method: string, bodyStr: string | null) {
  try {
    const isDoc = url.includes("/api/db/doc/");
    const baseApi = isDoc ? "/api/db/doc/" : "/api/db/col/";
    const docPathIndex = url.indexOf(baseApi);
    if (docPathIndex === -1) return;
    
    let fullPath = url.substring(docPathIndex);
    const qIndex = fullPath.indexOf('?');
    if (qIndex !== -1) {
      fullPath = fullPath.substring(0, qIndex);
    }
    
    const docPath = fullPath.replace(baseApi, "");
    
    let requestData: any = null;
    let isMerge = false;
    if (bodyStr) {
      try {
        const parsed = JSON.parse(bodyStr);
        requestData = parsed.data !== undefined ? parsed.data : parsed;
        isMerge = parsed.merge || false;
      } catch (err) {}
    }
    
    if (isDoc) {
      const segments = docPath.split("/");
      const docId = segments[segments.length - 1];
      const colPath = segments.slice(0, -1).join("/");
      const colUrl = `/api/db/col/${colPath}`;
      const docUrl = `/api/db/doc/${docPath}`;
      
      if (method === "DELETE") {
        localStorage.removeItem(`meb_cache:${docUrl}`);
        
        const cachedColStr = localStorage.getItem(`meb_cache:${colUrl}`);
        if (cachedColStr) {
          try {
            const colData = JSON.parse(cachedColStr);
            if (Array.isArray(colData)) {
              const filtered = colData.filter((item: any) => item.id !== docId);
              try {
                localStorage.setItem(`meb_cache:${colUrl}`, JSON.stringify(filtered));
              } catch (_) {}
            }
          } catch (_) {}
        }
      } else {
        const cachedDocStr = localStorage.getItem(`meb_cache:${docUrl}`);
        let currentDoc: any = {};
        if (cachedDocStr) {
          try {
            currentDoc = JSON.parse(cachedDocStr);
          } catch (_) {}
        }
        
        let updatedDoc: any;
        if (method === "PATCH" || isMerge) {
          updatedDoc = { ...currentDoc, ...requestData };
        } else {
          updatedDoc = requestData;
        }
        
        try {
          localStorage.setItem(`meb_cache:${docUrl}`, JSON.stringify(updatedDoc));
        } catch (_) {}
        
        const cachedColStr = localStorage.getItem(`meb_cache:${colUrl}`);
        let colData: any[] = [];
        if (cachedColStr) {
          try {
            const parsed = JSON.parse(cachedColStr);
            if (Array.isArray(parsed)) {
              colData = parsed;
            }
          } catch (_) {}
        }
        
        const idx = colData.findIndex((item: any) => item.id === docId);
        if (idx !== -1) {
          colData[idx] = { id: docId, data: updatedDoc };
        } else {
          colData.push({ id: docId, data: updatedDoc });
        }
        
        try {
          localStorage.setItem(`meb_cache:${colUrl}`, JSON.stringify(colData));
        } catch (_) {}
      }
    }
  } catch (err) {
    console.error("Local cache update error:", err);
  }
}

let isSyncing = false;
let lastFailedUrl = "";
let lastFailedCount = 0;

async function triggerSync() {
  if (isSyncing || typeof window === 'undefined' || !navigator.onLine) return;
  isSyncing = true;
  try {
    let syncedAny = false;
    while (true) {
      const currentQueueStr = localStorage.getItem("meb_pending_writes") || "[]";
      let currentQueue: any[] = [];
      try { currentQueue = JSON.parse(currentQueueStr); } catch (_) {}
      
      if (currentQueue.length === 0) break;
      
      const req = currentQueue[0];
      try {
        const res = await originalFetch(req.url, {
          method: req.method,
          headers: {
            ...req.headers,
            'Content-Type': 'application/json',
            'X-Offline-Sync': 'true'
          },
          body: req.body
        });
        
        const isSuccess = res.ok;
        const isClientError = res.status >= 400 && res.status < 500;
        
        if (isSuccess || isClientError) {
          syncedAny = true;
          lastFailedUrl = "";
          lastFailedCount = 0;
          const latestQueueStr = localStorage.getItem("meb_pending_writes") || "[]";
          let latestQueue: any[] = [];
          try { latestQueue = JSON.parse(latestQueueStr); } catch (_) {}
          
          if (latestQueue.length > 0) {
            latestQueue.shift();
            localStorage.setItem("meb_pending_writes", JSON.stringify(latestQueue));
          }
        } else {
          // Server error or temporary issue: handle potential head-of-line blocking
          if (lastFailedUrl === req.url) {
            lastFailedCount++;
          } else {
            lastFailedUrl = req.url;
            lastFailedCount = 1;
          }
          
          if (lastFailedCount >= 3) {
            console.error("Head-of-line blocking detected on server error. Skipping blocked request:", req.url);
            const latestQueueStr = localStorage.getItem("meb_pending_writes") || "[]";
            let latestQueue: any[] = [];
            try { latestQueue = JSON.parse(latestQueueStr); } catch (_) {}
            if (latestQueue.length > 0) {
              latestQueue.shift();
              localStorage.setItem("meb_pending_writes", JSON.stringify(latestQueue));
            }
            lastFailedUrl = "";
            lastFailedCount = 0;
            continue;
          }
          break;
        }
      } catch (err) {
        break;
      }
    }
    
    if (syncedAny && typeof window !== "undefined") {
      window.dispatchEvent(new CustomEvent("meb_sync_completed"));
    }
  } catch (err) {
    console.error("Sync error:", err);
  } finally {
    isSyncing = false;
  }
}

if (typeof window !== "undefined") {
  window.addEventListener('online', () => {
    triggerSync();
  });
  setInterval(triggerSync, 30000);
}

function applyPendingWrites(url: string, data: any) {
  try {
    const queueStr = localStorage.getItem("meb_pending_writes") || "[]";
    let queue: any[] = [];
    try { queue = JSON.parse(queueStr); } catch (_) {}
    if (queue.length === 0) return data;

    const isCol = url.includes("/api/db/col/");
    const baseApi = isCol ? "/api/db/col/" : "/api/db/doc/";
    const pathIndex = url.indexOf(baseApi);
    if (pathIndex === -1) return data;

    let fullPath = url.substring(pathIndex);
    const qIndex = fullPath.indexOf('?');
    if (qIndex !== -1) {
      fullPath = fullPath.substring(0, qIndex);
    }
    const targetPath = fullPath.replace(baseApi, "");

    let result = JSON.parse(JSON.stringify(data)); // Deep clone

    for (const req of queue) {
      const reqIsDoc = req.url.includes("/api/db/doc/");
      const reqBaseApi = reqIsDoc ? "/api/db/doc/" : "/api/db/col/";
      const reqPathIndex = req.url.indexOf(reqBaseApi);
      if (reqPathIndex === -1) continue;

      let reqFullPath = req.url.substring(reqPathIndex);
      const reqQIndex = reqFullPath.indexOf('?');
      if (reqQIndex !== -1) {
        reqFullPath = reqFullPath.substring(0, reqQIndex);
      }
      const reqDocPath = reqFullPath.replace(reqBaseApi, "");

      let requestData: any = null;
      let isMerge = false;
      if (req.body) {
        try {
          const parsed = JSON.parse(req.body);
          requestData = parsed.data !== undefined ? parsed.data : parsed;
          isMerge = parsed.merge || false;
        } catch (_) {}
      }

      if (isCol) {
        const segments = reqDocPath.split("/");
        const docId = segments[segments.length - 1];
        const colPath = segments.slice(0, -1).join("/");

        if (colPath === targetPath && Array.isArray(result)) {
          if (req.method === "DELETE") {
            result = result.filter((item: any) => item.id !== docId);
          } else {
            const idx = result.findIndex((item: any) => item.id === docId);
            let currentDocData = idx !== -1 ? result[idx].data : {};
            let updatedDocData: any;
            if (req.method === "PATCH" || isMerge) {
              updatedDocData = { ...currentDocData, ...requestData };
            } else {
              updatedDocData = requestData;
            }

            if (idx !== -1) {
              result[idx] = { id: docId, data: updatedDocData };
            } else {
              result.push({ id: docId, data: updatedDocData });
            }
          }
        }
      } else {
        if (reqDocPath === targetPath) {
          if (req.method === "DELETE") {
            result = null;
          } else {
            if (req.method === "PATCH" || isMerge) {
              result = { ...result, ...requestData };
            } else {
              result = requestData;
            }
          }
        }
      }
    }

    return result;
  } catch (err) {
    console.error("Error applying pending writes:", err);
    return data;
  }
}

const customFetch = async function (this: any, input: any, init?: any): Promise<Response> {
  const url = typeof input === "string" ? input : (input instanceof Request ? input.url : "");
  const method = (init && init.method) ? init.method.toUpperCase() : "GET";
  
  if (url.includes("/api/db/")) {
    const isWrite = ["POST", "PUT", "PATCH", "DELETE"].includes(method);
    
    if (!isWrite) {
      // GET Request: try fetch with 15s timeout, then fallback to cache
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 15000);
      try {
        const fetchOptions = { ...init, signal: controller.signal };
        const res = await originalFetch(url, fetchOptions);
        clearTimeout(timeoutId);
        
        if (res.ok) {
          try {
            const text = await res.text();
            try {
              let parsed = JSON.parse(text);
              parsed = applyPendingWrites(url, parsed);
              const processedText = JSON.stringify(parsed);
              try {
                localStorage.setItem(`meb_cache:${url}`, processedText);
              } catch (_) {}
              
              return new Response(processedText, {
                status: 200,
                headers: { "Content-Type": "application/json" }
              });
            } catch (jsonErr) {
              console.warn("Fetched stream failed JSON validation, using cache fallback:", url);
              const cached = localStorage.getItem(`meb_cache:${url}`);
              if (cached) {
                try {
                  const parsed = applyPendingWrites(url, JSON.parse(cached));
                  return new Response(JSON.stringify(parsed), {
                    status: 200,
                    headers: { "Content-Type": "application/json" }
                  });
                } catch (_) {
                  return new Response(cached, {
                    status: 200,
                    headers: { "Content-Type": "application/json" }
                  });
                }
              }
              if (url.includes("/api/db/doc/users/")) {
                return new Response(JSON.stringify({ error: "Invalid user profile data" }), {
                  status: 500,
                  headers: { "Content-Type": "application/json" }
                });
              }
              const emptyFallback = url.includes("/col/") ? "[]" : "{}";
              return new Response(emptyFallback, {
                status: 200,
                headers: { "Content-Type": "application/json" }
              });
            }
          } catch (streamErr) {
            console.warn("Fetched response stream failed to read, using cache fallback:", url);
            const cached = localStorage.getItem(`meb_cache:${url}`);
            if (cached) {
              try {
                const parsed = applyPendingWrites(url, JSON.parse(cached));
                return new Response(JSON.stringify(parsed), {
                  status: 200,
                  headers: { "Content-Type": "application/json" }
                });
              } catch (_) {
                return new Response(cached, {
                  status: 200,
                  headers: { "Content-Type": "application/json" }
                });
              }
            }
            if (url.includes("/api/db/doc/users/")) {
              return new Response(JSON.stringify({ error: "Failed to read user profile" }), {
                status: 500,
                headers: { "Content-Type": "application/json" }
              });
            }
            const emptyFallback = url.includes("/col/") ? "[]" : "{}";
            return new Response(emptyFallback, {
              status: 200,
              headers: { "Content-Type": "application/json" }
            });
          }
        } else {
          const cached = localStorage.getItem(`meb_cache:${url}`);
          if (cached) {
            try {
              const parsed = applyPendingWrites(url, JSON.parse(cached));
              return new Response(JSON.stringify(parsed), {
                status: 200,
                headers: { "Content-Type": "application/json" }
              });
            } catch (_) {
              return new Response(cached, {
                status: 200,
                headers: { "Content-Type": "application/json" }
              });
            }
          }
          if (url.includes("/api/db/doc/users/")) {
            return res;
          }
          const emptyFallback = url.includes("/col/") ? "[]" : "{}";
          return new Response(emptyFallback, {
            status: 200,
            headers: { "Content-Type": "application/json" }
          });
        }
      } catch (err) {
        clearTimeout(timeoutId);
        const cached = localStorage.getItem(`meb_cache:${url}`);
        if (cached) {
          try {
            const parsed = applyPendingWrites(url, JSON.parse(cached));
            return new Response(JSON.stringify(parsed), {
              status: 200,
              headers: { "Content-Type": "application/json" }
            });
          } catch (_) {
            return new Response(cached, {
              status: 200,
              headers: { "Content-Type": "application/json" }
            });
          }
        }
        if (url.includes("/api/db/doc/users/")) {
          return new Response(JSON.stringify({ error: "Network error loading user profile" }), {
            status: 503,
            headers: { "Content-Type": "application/json" }
          });
        }
        const emptyFallback = url.includes("/col/") ? "[]" : "{}";
        return new Response(emptyFallback, {
          status: 200,
          headers: { "Content-Type": "application/json" }
        });
      }
    } else {
      // Write request: POST, PUT, PATCH, DELETE
      let bodyStr: string | null = null;
      if (init && init.body) {
        if (typeof init.body === "string") {
          bodyStr = init.body;
        } else if (init.body instanceof Blob) {
          bodyStr = await init.body.text();
        }
      }
      
      const queueStr = localStorage.getItem("meb_pending_writes") || "[]";
      let queue: any[] = [];
      try { queue = JSON.parse(queueStr); } catch (_) {}
      
      if (typeof window !== "undefined" && navigator.onLine && queue.length === 0) {
        try {
          const res = await originalFetch(url, init);
          if (res.ok) {
            updateLocalCache(url, method, bodyStr);
            window.dispatchEvent(new CustomEvent("meb_sync_completed"));
          }
          return res;
        } catch (err) {
          console.warn("Direct online write fetch failed, falling back to offline sync queue:", err);
        }
      }
      
      updateLocalCache(url, method, bodyStr);
      
      queue.push({
        url,
        method,
        headers: init && init.headers ? (init.headers as any) : {},
        body: bodyStr,
        timestamp: Date.now()
      });
      localStorage.setItem("meb_pending_writes", JSON.stringify(queue));
      
      setTimeout(triggerSync, 100);
      
      return new Response(JSON.stringify({ success: true, offline: true }), {
        status: 200,
        headers: { "Content-Type": "application/json" }
      });
    }
  }
  
  return originalFetch.apply(this, arguments as any);
};

// Global intercept with safe try-catch handlers to prevent getter errors
try {
  try {
    (window as any).fetch = customFetch;
  } catch (err) {
    try {
      Object.defineProperty(window, 'fetch', {
        value: customFetch,
        writable: true,
        configurable: true
      });
    } catch (err2) {
      try {
        Object.defineProperty(Object.getPrototypeOf(window), 'fetch', {
          value: customFetch,
          writable: true,
          configurable: true
        });
      } catch (err3) {
        console.warn("Global fetch interception is disabled by sandbox/security context. Falling back to local module shadowing.", err3);
      }
    }
  }
} catch (e) {
  console.warn("Fetch interceptor setup encountered external issues:", e);
}

// Local module shadow to guarantee it is always used within App.tsx context
const fetch = customFetch;
// --- END OF OFFLINE CACHE AND SYNC ENGINE ---

