function collection(db: any, path: string, ...rest: any[]) { 
  const fullPath = [path, ...rest].join('/');
  return { path: fullPath }; 
}

const activePollingSubscriptions = new Map<string, {
  url: string;
  isCol: boolean;
  subscribers: Set<{
    callback: (snap: any) => void;
    errorCb?: (err: any) => void;
  }>;
  interval: any;
  lastFetchedText: string | null;
}>();

function onSnapshot(ref: any, callback: (snap: any) => void, errorCb?: (err: any) => void, intervalMs: number = 15000) { 
  const isCol = ref.path.split('/').length % 2 !== 0;
  const colUrl = `/api/db/col/${ref.path}`;
  const docUrl = `/api/db/doc/${ref.path}`;
  const url = isCol ? colUrl : docUrl;
  
  const subscriber = { callback, errorCb };
  
  // 1. Immediately invoke callback with cached data if available (instant 0ms render)
  try {
    const cachedStr = localStorage.getItem(`meb_cache:${url}`);
    if (cachedStr) {
      const parsed = JSON.parse(cachedStr);
      if (isCol && Array.isArray(parsed)) {
        setTimeout(() => {
          callback({
            docs: parsed.map((d: any) => ({
              id: d.id,
              data: () => d.data,
              exists: () => true
            })),
            size: parsed.length
          });
        }, 0);
      } else if (!isCol && parsed && typeof parsed === "object") {
        setTimeout(() => {
          callback({
            exists: () => true,
            data: () => parsed,
            id: ref.path.split('/').pop()
          });
        }, 0);
      }
    }
  } catch (e) {
    console.warn("Error loading cached snapshot:", e);
  }
  
  // 2. Register in shared polling registry
  let group = activePollingSubscriptions.get(url);
  const isNewGroup = !group;
  
  if (isNewGroup) {
    group = {
      url,
      isCol,
      subscribers: new Set(),
      interval: null,
      lastFetchedText: localStorage.getItem(`meb_cache:${url}`)
    };
    activePollingSubscriptions.set(url, group);
  }
  
  group!.subscribers.add(subscriber);
  
  const fetchGroupSnapshot = async () => {
    if (!group) return;
    try {
      const res = await fetch(url);
      if (res.ok) {
        const text = await res.text();
        
        // Prevent duplicate callback invocations if data hasn't changed
        if (text === group.lastFetchedText) {
          return;
        }
        
        // JSON validation
        let parsed: any;
        try {
          parsed = JSON.parse(text);
        } catch (jsonErr) {
          console.warn("Polled snapshot returned invalid JSON for:", url);
          return;
        }
        
        group.lastFetchedText = text;
        try {
          localStorage.setItem(`meb_cache:${url}`, text);
        } catch (_) {}
        
        // Notify all subscribers of the collection or document
        for (const sub of group.subscribers) {
          try {
            if (isCol && Array.isArray(parsed)) {
              sub.callback({
                docs: parsed.map((d: any) => ({
                  id: d.id,
                  data: () => d.data,
                  exists: () => true
                })),
                size: parsed.length
              });
            } else if (!isCol && parsed && typeof parsed === "object") {
              sub.callback({
                exists: () => true,
                data: () => parsed,
                id: ref.path.split('/').pop()
              });
            }
          } catch (cbErr) {
            console.error("Error in subscriber callback:", cbErr);
          }
        }
      } else if (res.status === 404 && !isCol) {
        group.lastFetchedText = "null";
        for (const sub of group.subscribers) {
          try {
            sub.callback({ exists: () => false, data: () => null });
          } catch (_) {}
        }
      }
    } catch (e) {
      for (const sub of group.subscribers) {
        if (sub.errorCb) {
          try { sub.errorCb(e); } catch (_) {}
        } else {
          console.error("Snapshot shared error:", e);
        }
      }
    }
  };
  
  // Only register one interval/fetch per path
  if (isNewGroup) {
    fetchGroupSnapshot();
    group!.interval = setInterval(fetchGroupSnapshot, intervalMs);
  }
  
  const handleSyncComplete = () => {
    fetchGroupSnapshot();
  };
  
  if (typeof window !== "undefined") {
    window.addEventListener("meb_sync_completed", handleSyncComplete);
  }
  
  return () => {
    if (!group) return;
    group.subscribers.delete(subscriber);
    
    if (typeof window !== "undefined") {
      window.removeEventListener("meb_sync_completed", handleSyncComplete);
    }
    
    if (group.subscribers.size === 0) {
      clearInterval(group.interval);
      activePollingSubscriptions.delete(url);
    }
  };
}

function doc(db: any, col: string, ...rest: any[]) { 
  const path = [col, ...rest].join('/');
  return { path }; 
}

async function getDoc(docRef: any) { 
  const res = await fetch(`/api/db/doc/${docRef.path}`);
  if (res.ok) {
    const data = await res.json();
    return {
      exists: () => true,
      data: () => data
    };
  }
  return { exists: () => false };
}

async function setDoc(docRef: any, data: any, options?: { merge?: boolean }) {
  await fetch(`/api/db/doc/${docRef.path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ data, merge: options?.merge })
  });
  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("meb_sync_completed"));
  }
}

async function updateDoc(docRef: any, data: any, options?: any) { 
  await fetch(`/api/db/doc/${docRef.path}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ data, merge: options?.merge })
  });
  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("meb_sync_completed"));
  }
}

async function deleteDoc(docRef: any) { 
  await fetch(`/api/db/doc/${docRef.path}`, {
    method: 'DELETE'
  });
  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("meb_sync_completed"));
  }
}

const reportPriceChange = async (companyId: string, userId: string, userName: string, materialId: string, oldPrice: number, newPrice: number) => {
  if (!companyId || !userId || oldPrice === newPrice) return;
  try {
    await fetch(`/api/db/doc/companies/${companyId}/priceHistory/${Math.random().toString(36).substr(2, 9)}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ data: {
        materialId,
        oldPrice,
        newPrice,
        userId,
        userName,
        timestamp: new Date().toISOString()
      }})
    });
  } catch (err) {
    console.error("Error logging price change", err);
  }
};

async function addDoc(colRef: any, data: any) {
  const id = Math.random().toString(36).substr(2, 9);
  const path = `${colRef.path}/${id}`;
  await fetch(`/api/db/doc/${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ data })
  });
  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("meb_sync_completed"));
  }
  return { id, path, data };
}

function writeBatch(db: any) {
  const operations: any[] = [];
  return {
    set: (ref: any, data: any, options?: any) => operations.push({ type: 'set', ref, data, options }),
    update: (ref: any, data: any, options?: any) => operations.push({ type: 'update', ref, data, options }),
    delete: (ref: any) => operations.push({ type: 'delete', ref }),
    commit: async () => {
      for (const op of operations) {
        if (op.type === 'set') await setDoc(op.ref, op.data, op.options);
        if (op.type === 'update') await updateDoc(op.ref, op.data, op.options);
        if (op.type === 'delete') await deleteDoc(op.ref);
      }
    }
  };
}

