                                className="w-full px-2.5 py-1.5 text-xs border border-gray-200 rounded-lg bg-white outline-none focus:ring-1 focus:ring-emerald-500 font-semibold text-gray-700"
                              >
                                <option value="">-- Все разделы --</option>
