  const upsertEdgeToPriceList = async (decor: string, thickness: string, price: number, brandLdsp: string) => {
    if (!companyData?.id || price <= 0 || !decor || decor === "Не указан") return;

    // Найдем соответствующий бренд кромки по таблице совместимости
    const edgeBrands = LDSP_TO_EDGE_BRANDS[brandLdsp] || [];
    const edgeBrand = edgeBrands[0] || "Egger"; // По умолчанию Egger, если не нашли

    // Поищем в catalogProducts существующую кромку с таким декором, толщиной и категорией "Кромочные материалы"
    const existing = catalogProducts.find(p => 
      p.category === "Кромочные материалы" && 
      p.decor === decor && 
      p.thickness === thickness
    );

    const pId = existing?.id || Math.random().toString(36).substr(2, 9);
    const productData = {
      id: pId,
      category: "Кромочные материалы",
      decor: decor,
      thickness: thickness,
      brand: edgeBrand,
      price: price,
      name: `Кромка ${decor} ${thickness}мм`,
      compatibility: brandLdsp,
      updatedAt: new Date().toISOString(),
      status: 'approved'
    };

    try {
      await setDoc(
        doc(db, "companies", companyData.id, "products", pId),
        productData,
        { merge: true }
      );
      console.log("Upserted edge to price list:", productData);
    } catch (e) {
      console.error("Error upserting edge to price list:", e);
    }
  };

  const saveProduct = async (product: any) => {
    console.log("saveProduct called, companyData?.id:", companyData?.id, "userData?.uid:", userData?.uid, "product:", product);
    if (!companyData?.id || !userData?.uid) {
      console.log("saveProduct failed: missing companyData or userData");
      return;
    }
    try {
      const isNew = !product.id;
      const pId = product.id || Math.random().toString(36).substr(2, 9);
      console.log("Saving product, pId:", pId, "isNew:", isNew);
      
      const finalProduct = {
        ...product,
        id: pId,
        updatedAt: new Date().toISOString(),
      };

      if (isNew) {
        finalProduct.status = userRole === 'admin' ? 'approved' : 'pending';
        finalProduct.addedBy = userData.uid;
      }

      console.log("Final product to save:", finalProduct);
      
      // 1. Optimistic update so the product appears in the UI instantly (0ms delay)
      setOwnProducts((prev) => {
        const idx = prev.findIndex((p) => String(p.id) === String(pId));
        if (idx !== -1) {
          const updated = [...prev];
          updated[idx] = finalProduct;
          return updated;
        } else {
          return [finalProduct, ...prev];
        }
      });

      // 2. Perform write and await it so we know it has successfully reached the server
      await setDoc(
        doc(db, "companies", companyData.id, "products", pId),
        finalProduct,
      );
      console.log("setDoc completed successfully");

      if (isNew && finalProduct.status === 'pending') {
        showAlert("На проверке", "Товар успешно сохранен и отправлен на модерацию");
      } else {
        showAlert("Успех", "Товар успешно сохранен");
      }
    } catch (error) {
      console.error("Error in saveProduct:", error);
      handleDbError(
        error,
        OperationType.WRITE,
        `companies/${companyData.id}/products`,
      );
      throw error; // Rethrow to let handleCreateProduct handle it in its catch block
    }
  };

